    29→     *
    30→     * @return a single PyIntObj selected from the random domain
    31→     */
    32→    @Override
    33→    public PyIntObj genRandVal() {
    34→        return new PyIntObj(this.ranDomainChoice().intValue());
    35→    }
    36→}

