   199→        args.add(filename);
   200→        args.add(this.funcName);
   201→
   202→        // Add each argument as a string; the footer will take care of converting these to
   203→        // Python objects before invoking the function under test
   204→        TestCase test = this.tests.get(testIndex);
   205→        for (APyObj arg : test.getArgs()) {
   206→            args.add(arg.toString());
   207→        }
   208→        return args;
   209→    }
