package main.rice.parse;

import main.rice.node.APyNode;
import java.util.List;

/**
 * A simple data class representing a parsed configuration file.
 */
public class ConfigFile {

    private final String funcName;
    private final List<APyNode<?>> nodes;
    private final int numRand;

    /**
     * Constructs a ConfigFile with the given function name, list of nodes, and number
     * of random test cases.
     *
     * @param funcName the name of the function under test
     * @param nodes    the list of APyNodes representing the parameter types and domains
     * @param numRand  the number of random test cases to generate
     */
    public ConfigFile(String funcName, List<APyNode<?>> nodes, int numRand) {
        this.funcName = funcName;
        this.nodes = nodes;
        this.numRand = numRand;
    }

    /**
     * Returns the function name.
     *
     * @return the function name
     */
    public String getFuncName() {
        return this.funcName;
    }

    /**
     * Returns the number of random test cases.
     *
     * @return the number of random test cases
     */
    public int getNumRand() {
        return this.numRand;
    }

    /**
     * Returns the list of APyNodes for the function parameters.
     *
     * @return the list of APyNodes
     */
    public List<APyNode<?>> getNodes() {
        return this.nodes;
    }
}

package main.rice.parse;

import main.rice.node.*;
import org.json.JSONArray;
import org.json.JSONException;
import org.json.JSONObject;

import java.util.*;

/**
 * Parses JSON configuration files into ConfigFile objects.
 */
public class ConfigFileParser {

    /**
     * Parses the given JSON string into a ConfigFile.
     *
     * @param jsonStr the JSON configuration string
     * @return the parsed ConfigFile
     * @throws InvalidConfigException if the JSON is invalid or malformed
     */
    public ConfigFile parse(String jsonStr) throws InvalidConfigException {
        // Step 1: Parse as JSON
        JSONObject json;
        try {
            json = new JSONObject(jsonStr);
        } catch (JSONException e) {
            throw new InvalidConfigException("Invalid JSON: " + e.getMessage());
        }

        // Step 2: Extract required fields
        String fname = extractString(json, "fname");
        JSONArray typesArr = extractArray(json, "types");
        JSONArray exDomainArr = extractArray(json, "exhaustive domain");
        JSONArray ranDomainArr = extractArray(json, "random domain");
        int numRand = extractInt(json, "num random");

        if (numRand < 0) {
            throw new InvalidConfigException("num random must be non-negative, got: " + numRand);
        }

        // Step 3: Convert arrays to lists of strings
        List<String> typeStrs = extractStringList(typesArr, "types");
        List<String> exDomainStrs = extractStringList(exDomainArr, "exhaustive domain");
        List<String> ranDomainStrs = extractStringList(ranDomainArr, "random domain");

        // Step 4: Validate array lengths match
        if (typeStrs.size() != exDomainStrs.size()) {
            throw new InvalidConfigException(
                "exhaustive domain length (" + exDomainStrs.size()
                + ") does not match types length (" + typeStrs.size() + ")");
        }
        if (typeStrs.size() != ranDomainStrs.size()) {
            throw new InvalidConfigException(
                "random domain length (" + ranDomainStrs.size()
                + ") does not match types length (" + typeStrs.size() + ")");
        }

        // Step 5: Parse each type and set its domains
        List<APyNode<?>> nodes = new ArrayList<>();
        for (int i = 0; i < typeStrs.size(); i++) {
            APyNode<?> node = parseType(typeStrs.get(i));
            parseNodeDomain(exDomainStrs.get(i), node, true);
            parseNodeDomain(ranDomainStrs.get(i), node, false);
            nodes.add(node);
        }

        return new ConfigFile(fname, nodes, numRand);
    }

    // ==================== JSON EXTRACTION HELPERS ====================

    private String extractString(JSONObject json, String key) throws InvalidConfigException {
        try {
            return json.getString(key);
        } catch (JSONException e) {
            throw new InvalidConfigException("Missing or invalid field '" + key + "': " + e.getMessage());
        }
    }

    private JSONArray extractArray(JSONObject json, String key) throws InvalidConfigException {
        try {
            return json.getJSONArray(key);
        } catch (JSONException e) {
            throw new InvalidConfigException("Missing or invalid array field '" + key + "': " + e.getMessage());
        }
    }

    private int extractInt(JSONObject json, String key) throws InvalidConfigException {
        try {
            return json.getInt(key);
        } catch (JSONException e) {
            throw new InvalidConfigException("Missing or invalid integer field '" + key + "': " + e.getMessage());
        }
    }

    private List<String> extractStringList(JSONArray arr, String fieldName) throws InvalidConfigException {
        List<String> result = new ArrayList<>();
        for (int i = 0; i < arr.length(); i++) {
            Object elem = arr.get(i);
            if (!(elem instanceof String)) {
                throw new InvalidConfigException(
                    "Field '" + fieldName + "' must be an array of strings, but element " + i
                    + " is: " + elem);
            }
            result.add((String) elem);
        }
        return result;
    }

    // ==================== TYPE PARSING ====================

    /**
     * Parses a type string into an APyNode. Throws InvalidConfigException if the type
     * string is not valid.
     */
    @SuppressWarnings({"rawtypes", "unchecked"})
    private APyNode<?> parseType(String typeStr) throws InvalidConfigException {
        if (typeStr.equals("bool")) {
            return new PyBoolNode();
        }
        if (typeStr.equals("int")) {
            return new PyIntNode();
        }
        if (typeStr.equals("float")) {
            return new PyFloatNode();
        }
        if (typeStr.startsWith("str(") && typeStr.endsWith(")")) {
            String chars = typeStr.substring(4, typeStr.length() - 1);
            if (chars.isEmpty()) {
                throw new InvalidConfigException("str type must have non-empty character domain: " + typeStr);
            }
            return new PyStringNode(chars);
        }
        if (typeStr.startsWith("list(") && typeStr.endsWith(")")) {
            String inner = typeStr.substring(5, typeStr.length() - 1);
            APyNode child = parseType(inner);
            return new PyListNode(child);
        }
        if (typeStr.startsWith("set(") && typeStr.endsWith(")")) {
            String inner = typeStr.substring(4, typeStr.length() - 1);
            APyNode child = parseType(inner);
            return new PySetNode(child);
        }
        if (typeStr.startsWith("tuple(") && typeStr.endsWith(")")) {
            String inner = typeStr.substring(6, typeStr.length() - 1);
            APyNode child = parseType(inner);
            return new PyTupleNode(child);
        }
        if (typeStr.startsWith("dict(") && typeStr.endsWith(")")) {
            String inner = typeStr.substring(5, typeStr.length() - 1);
            // Split on ':' at depth 0
            int splitIdx = findTopLevelColon(inner);
            if (splitIdx < 0) {
                throw new InvalidConfigException("dict type requires 'Key:Value' inside parens: " + typeStr);
            }
            String keyStr = inner.substring(0, splitIdx);
            String valStr = inner.substring(splitIdx + 1);
            APyNode keyNode = parseType(keyStr);
            APyNode valNode = parseType(valStr);
            return new PyDictNode(keyNode, valNode);
        }
        throw new InvalidConfigException("Unknown or invalid type: " + typeStr);
    }

    // ==================== DOMAIN PARSING ====================

    /**
     * Parses the domain string and sets the ex or ran domain on the given node (and
     * recursively on its children).
     *
     * @param domainStr the domain string
     * @param node      the node to set the domain on
     * @param isEx      true to set exhaustive domain, false to set random domain
     */
    private void parseNodeDomain(String domainStr, APyNode<?> node, boolean isEx)
            throws InvalidConfigException {

        if (node instanceof PyBoolNode) {
            List<Number> vals = parseLeafValues(domainStr, "bool");
            if (isEx) node.setExDomain(vals);
            else node.setRanDomain(vals);

        } else if (node instanceof PyIntNode) {
            List<Number> vals = parseLeafValues(domainStr, "int");
            if (isEx) node.setExDomain(vals);
            else node.setRanDomain(vals);

        } else if (node instanceof PyFloatNode) {
            List<Number> vals = parseLeafValues(domainStr, "float");
            if (isEx) node.setExDomain(vals);
            else node.setRanDomain(vals);

        } else if (node instanceof PyStringNode) {
            // String domain is just a size domain (non-negative integers)
            List<Number> vals = parseLeafValues(domainStr, "size");
            if (isEx) node.setExDomain(vals);
            else node.setRanDomain(vals);

        } else {
            // Collection type: list, set, tuple, or dict
            // Format: outerDomain(innerDomain)
            int firstParen = domainStr.indexOf('(');
            if (firstParen < 0) {
                throw new InvalidConfigException(
                    "Expected '(' in collection domain but found none: " + domainStr);
            }

            // Find the matching closing paren
            int depth = 0;
            int lastParen = -1;
            for (int i = firstParen; i < domainStr.length(); i++) {
                char c = domainStr.charAt(i);
                if (c == '(') depth++;
                else if (c == ')') {
                    depth--;
                    if (depth == 0) {
                        lastParen = i;
                        break;
                    }
                }
            }

            if (lastParen < 0) {
                throw new InvalidConfigException("Unmatched '(' in domain: " + domainStr);
            }
            if (lastParen != domainStr.length() - 1) {
                throw new InvalidConfigException(
                    "Extra characters after closing ')' in domain: " + domainStr);
            }

            String outerPart = domainStr.substring(0, firstParen);
            String innerPart = domainStr.substring(firstParen + 1, lastParen);

            // Outer domain must be non-negative integers (size of collection)
            List<Number> outerVals = parseLeafValues(outerPart, "size");
            if (isEx) node.setExDomain(outerVals);
            else node.setRanDomain(outerVals);

            if (node instanceof PyDictNode) {
                // Inner part is "keyDomain:valueDomain" - split on top-level colon
                int colonIdx = findTopLevelColon(innerPart);
                if (colonIdx < 0) {
                    throw new InvalidConfigException(
                        "dict domain requires 'keyDomain:valueDomain' inside parens: " + domainStr);
                }
                String keyPart = innerPart.substring(0, colonIdx);
                String valPart = innerPart.substring(colonIdx + 1);
                parseNodeDomain(keyPart, node.getLeftChild(), isEx);
                parseNodeDomain(valPart, node.getRightChild(), isEx);
            } else {
                // list, set, or tuple - single inner domain
                parseNodeDomain(innerPart, node.getLeftChild(), isEx);
            }
        }
    }

    // ==================== LEAF VALUE PARSING ====================

    /**
     * Parses a leaf domain string (either "a~b" range or "[v1, v2, ...]" explicit list)
     * and returns a deduplicated list of values.
     *
     * @param domainStr the domain string
     * @param type      the type context: "bool", "int", "float", or "size"
     */
    private List<Number> parseLeafValues(String domainStr, String type)
            throws InvalidConfigException {
        if (domainStr.startsWith("[") && domainStr.endsWith("]")) {
            return parseExplicitList(domainStr, type);
        } else if (domainStr.contains("~")) {
            return parseRange(domainStr, type);
        } else {
            throw new InvalidConfigException(
                "Invalid domain format (expected '[...]' or 'a~b'): " + domainStr);
        }
    }

    /**
     * Parses a range domain "a~b" into a list [a, a+1, ..., b].
     */
    private List<Number> parseRange(String domainStr, String type)
            throws InvalidConfigException {
        String[] parts = domainStr.split("~");
        if (parts.length != 2) {
            throw new InvalidConfigException("Invalid range format: " + domainStr);
        }
        int lower, upper;
        try {
            lower = Integer.parseInt(parts[0]);
            upper = Integer.parseInt(parts[1]);
        } catch (NumberFormatException e) {
            throw new InvalidConfigException(
                "Range bounds must be integers, got: " + domainStr);
        }
        if (lower > upper) {
            throw new InvalidConfigException(
                "Lower bound " + lower + " exceeds upper bound " + upper + " in range: " + domainStr);
        }
        // For size domains, must be non-negative
        if (type.equals("size") && lower < 0) {
            throw new InvalidConfigException(
                "Size domain values must be non-negative, got lower bound: " + lower);
        }
        // For bool domains, must be in [0, 1]
        if (type.equals("bool")) {
            if (lower < 0 || upper > 1) {
                throw new InvalidConfigException(
                    "Bool domain values must be 0 or 1, got range: " + domainStr);
            }
        }

        List<Number> result = new ArrayList<>();
        for (int i = lower; i <= upper; i++) {
            result.add(i);
        }
        return result;
    }

    /**
     * Parses an explicit list domain "[v1, v2, ...]" and returns a deduplicated list.
     */
    private List<Number> parseExplicitList(String domainStr, String type)
            throws InvalidConfigException {
        // Strip the outer [ and ]
        String inner = domainStr.substring(1, domainStr.length() - 1);
        if (inner.isEmpty()) {
            return new ArrayList<>();
        }
        String[] parts = inner.split(",");

        // Use LinkedHashSet to deduplicate while preserving insertion order
        LinkedHashSet<Number> seen = new LinkedHashSet<>();
        for (String part : parts) {
            String trimmed = part.trim();
            Number val = parseValue(trimmed, type);
            seen.add(val);
        }
        return new ArrayList<>(seen);
    }

    /**
     * Parses a single value string according to the type constraint.
     */
    private Number parseValue(String valStr, String type) throws InvalidConfigException {
        switch (type) {
            case "bool": {
                int v;
                try {
                    v = Integer.parseInt(valStr);
                } catch (NumberFormatException e) {
                    throw new InvalidConfigException(
                        "Bool domain value must be integer 0 or 1, got: " + valStr);
                }
                if (v < 0 || v > 1) {
                    throw new InvalidConfigException(
                        "Bool domain value must be 0 or 1, got: " + v);
                }
                return v;
            }
            case "int": {
                try {
                    return Integer.parseInt(valStr);
                } catch (NumberFormatException e) {
                    throw new InvalidConfigException(
                        "Int domain value must be an integer, got: " + valStr);
                }
            }
            case "size": {
                int v;
                try {
                    v = Integer.parseInt(valStr);
                } catch (NumberFormatException e) {
                    throw new InvalidConfigException(
                        "Size domain value must be a non-negative integer, got: " + valStr);
                }
                if (v < 0) {
                    throw new InvalidConfigException(
                        "Size domain value must be non-negative, got: " + v);
                }
                return v;
            }
            case "float": {
                try {
                    if (valStr.contains(".")) {
                        return Double.parseDouble(valStr);
                    } else {
                        return Integer.parseInt(valStr);
                    }
                } catch (NumberFormatException e) {
                    throw new InvalidConfigException(
                        "Float domain value must be a number, got: " + valStr);
                }
            }
            default:
                throw new InvalidConfigException("Unknown type for value parsing: " + type);
        }
    }

    // ==================== UTILITY HELPERS ====================

    /**
     * Finds the index of the first ':' at paren depth 0 in the given string.
     * Returns -1 if no such colon exists.
     */
    private int findTopLevelColon(String s) {
        int depth = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (c == '(') depth++;
            else if (c == ')') depth--;
            else if (c == ':' && depth == 0) return i;
        }
        return -1;
    }
}

package main.rice;

import main.rice.basegen.BaseSetGenerator;
import main.rice.concisegen.ConciseSetGenerator;
import main.rice.node.APyNode;
import main.rice.parse.ConfigFile;
import main.rice.parse.ConfigFileParser;
import main.rice.parse.InvalidConfigException;
import main.rice.test.TestCase;
import main.rice.test.TestResults;
import main.rice.test.Tester;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.List;
import java.util.Set;

/**
 * Entry point that ties together all components: parsing, test generation, testing,
 * and concise set selection.
 */
public class Main {

    /**
     * Generates a concise set of test cases that covers all known buggy implementations.
     *
     * @param args args[0] = path to config file, args[1] = path to solution file,
     *             args[2] = path to directory of implementations to test
     * @return a minimal set of test cases that catches all known buggy implementations
     */
    public static Set<TestCase> generateTests(String[] args)
            throws IOException, InvalidConfigException, InterruptedException {

        // Step 1: Read and parse the config file
        String configContents = Files.readString(Paths.get(args[0]));
        ConfigFileParser parser = new ConfigFileParser();
        ConfigFile config = parser.parse(configContents);

        String funcName = config.getFuncName();
        int numRand = config.getNumRand();
        List<APyNode<?>> nodes = config.getNodes();

        // Step 2: Generate the base set of test cases
        BaseSetGenerator baseGen = new BaseSetGenerator(nodes, numRand);
        List<TestCase> testCases = baseGen.genBaseSet();

        // Step 3: Run the test suite on the solution and implementations
        Tester tester = new Tester(funcName, args[1], args[2], testCases);
        tester.computeExpectedResults();
        TestResults results = tester.runTests();

        // Step 4: Select the minimal (concise) set of test cases
        return ConciseSetGenerator.setCover(results);
    }
}

